61	>
62	class Sm100FmhaBwd {
63	public:
64	  /// Argument structure: User API
65	  struct Arguments {
66	    // Q K D D_VO HB
67	    ProblemShape problem_shape;
68	
69	    const Element* ptr_Q;
70	    cute::tuple<int, cute::_1, cute::tuple<int, int>> stride_Q;
71	    const Element* ptr_K;
72	    cute::tuple<int, cute::_1, cute::tuple<int, int>> stride_K;
73	    const Element* ptr_V;
74	    cute::tuple<int, cute::_1, cute::tuple<int, int>> stride_V;
75	
76	    const Element* ptr_O;
77	    cute::tuple<int, cute::_1, cute::tuple<int, int>> stride_O;
78	    const ElementAccumulator* ptr_LSE;
79	    cute::tuple<cute::_1, cute::tuple<int, int>> stride_LSE;
80	
81	    const Element* ptr_dO;
82	    cute::tuple<int, cute::_1, cute::tuple<int, int>> stride_dO;
83	
84	    Element* ptr_dQ;
85	    cute::tuple<int, cute::_1, cute::tuple<int, int>> stride_dQ;
86	    Element* ptr_dK;
87	    cute::tuple<int, cute::_1, cute::tuple<int, int>> stride_dK;
88	    Element* ptr_dV;
89	    cute::tuple<int, cute::_1, cute::tuple<int, int>> stride_dV;
90	
91	    ElementAccumulator softmax_scale;
92	
93	    cutlass::KernelHardwareInfo hw_info;
94	  };
95	
96	  using OperationSumOdO = cutlass::fmha::device::FMHA<
97	    cutlass::fmha::kernel::FmhaKernelBwdSumOdO<ProblemShape, Element, ElementAccumulator>
98	  >;
99	  using OperationConvert = cutlass::fmha::device::FMHA<
100	    cutlass::fmha::kernel::FmhaKernelBwdConvert<ProblemShape, Element, ElementAccumulator>
101	  >;
102	
103	  using OperationMha= cutlass::fmha::device::FMHA<
104	      cutlass::fmha::kernel::Sm100FmhaBwdKernelTmaWarpSpecialized<
105	          ProblemShape, Element, ElementAccumulator, TileShape, Mask
106	      >
107	  >;
108	
109	  using OperationMla = cutlass::fmha::device::FMHA<
110	      cutlass::fmha::kernel::Sm100FmhaBwdMlaKernelTmaWarpSpecialized<
111	          ProblemShape, Element, ElementAccumulator, TileShape, Mask
112	      >
113	  >;
114	
115	  using Operation = std::conditional_t<IsMla, OperationMla, OperationMha>;
116	
117	  using Kernel = typename Operation::Kernel;
118	
119	  struct Params {
120	    OperationSumOdO op_sum_OdO;
121	    Operation op;
122	    OperationConvert op_convert;
123	    ElementAccumulator* dQ_acc;
124	    size_t dQ_acc_size;
125	  };
126	
127	private:
128	  Params params_;
129	
130	  static typename OperationSumOdO::Arguments to_sum_OdO_arguments(
131	        Arguments const& args,
132	        ElementAccumulator* sum_odo = nullptr,
133	        ElementAccumulator* scaled_lse = nullptr) {
134	    using namespace cute;
135	    auto [Q_, K, D, D_VO, HB] = args.problem_shape;
136	    auto [H, B] = HB;
137	    D = cutlass::round_up(D, 8);  // Alignment
138	    int Q = cutlass::round_up(static_cast<int>(Q_), 8);  // Alignment
139	    auto stride_sum_OdO = make_stride(_1{}, make_stride(Q, Q*H));
140	    auto stride_scaled_lse = make_stride(_1{}, make_stride(Q, Q*H));
141	    auto log2_e = log2f(expf(1.0f));
142	    return typename OperationSumOdO::Arguments {
143	      args.problem_shape,
144	      args.ptr_O, args.stride_O,
145	      args.ptr_dO, args.stride_dO,
146	      sum_odo, stride_sum_OdO,
147	      args.ptr_LSE, args.stride_LSE,
148	      scaled_lse, stride_scaled_lse,
149	      -1.0f, -log2_e
150	    };
151	  }
152	
153	  static typename OperationConvert::Arguments to_convert_arguments(Arguments const& args, ElementAccumulator* src = nullptr) {
154	    using namespace cute;
155	    auto [Q_, K, D, D_VO, HB] = args.problem_shape;
156	    auto [H, B] = HB;
157	    D = cutlass::round_up(D, 8);  // Alignment
158	    int Q = cutlass::round_up(static_cast<int>(Q_), 8);  // Alignment
159	    auto stride_src_dQ = make_stride(D, _1{}, make_stride(D*Q, D*Q*H));
160	    return typename OperationConvert::Arguments {
161	      args.problem_shape,
162	      src, stride_src_dQ,
163	      nullptr, stride_src_dQ,
164	      nullptr, stride_src_dQ,
165	      args.ptr_dQ, args.stride_dQ,
166	      nullptr, args.stride_dK,
167	      nullptr, args.stride_dV,
168	      args.softmax_scale
169	    };
170	  }
171	
172	  static typename Operation::Arguments to_bwd_arguments(
173	      Arguments const& args,
174	      ElementAccumulator* sum_OdO = nullptr, cute::tuple<cute::_1, cute::tuple<int, int>> const& stride_sum_OdO = {},
175	      ElementAccumulator* scaled_lse = nullptr, cute::tuple<cute::_1, cute::tuple<int, int>> const& stride_scaled_lse = {},
176	      ElementAccumulator* dQ_acc = nullptr, cute::tuple<int, cute::_1, cute::tuple<int, int>> const& stride_dQ = {}) {
177	
178	    return typename Operation::Arguments{
179	      args.problem_shape,
180	      { args.ptr_Q,  args.stride_Q,
181	        args.ptr_K,  args.stride_K,
182	        args.ptr_V,  args.stride_V,
183	        args.ptr_dO, args.stride_dO,
184	        scaled_lse, stride_scaled_lse,
185	        sum_OdO, stride_sum_OdO,
186	        dQ_acc, stride_dQ,
187	        args.softmax_scale },
188	      { args.ptr_dK, args.stride_dK,
189	        args.ptr_dV, args.stride_dV },
190	      args.hw_info
191	    };
192	  }
193	
194	public:
195	
196	  /// Determines whether the GEMM can execute the given problem.
197	  static Status
198	  can_implement(Arguments const& args) {
199	    Status status = Status::kSuccess;
200	
